class Solution:
    def isSolvable(self, words, result):
        rows = words + [result]
        if any(len(w) > len(result) for w in words):
            return False
        letters = set()
        for w in rows:
            letters.update(w)
        if len(letters) > 10:
            return False
        leading = set(w[0] for w in rows if len(w) > 1)
        maxlen = len(result)
        assigned = {}
        used = [False] * 10
        def dfs(col, row, carry):
            if col == maxlen:
                return carry == 0
            if row < len(words):
                w = words[row]
                if col >= len(w):
                    return dfs(col, row + 1, carry)
                ch = w[len(w) - 1 - col]
                if ch in assigned:
                    return dfs(col, row + 1, carry + assigned[ch])
                for d in range(10):
                    if used[d] or (d == 0 and ch in leading):
                        continue
                    assigned[ch] = d
                    used[d] = True
                    if dfs(col, row + 1, carry + d):
                        used[d] = False
                        del assigned[ch]
                        return True
                    used[d] = False
                    del assigned[ch]
                return False
            rch = result[maxlen - 1 - col]
            digit = carry % 10
            ncarry = carry // 10
            if rch in assigned:
                if assigned[rch] != digit:
                    return False
                return dfs(col + 1, 0, ncarry)
            if used[digit] or (digit == 0 and rch in leading):
                return False
            assigned[rch] = digit
            used[digit] = True
            if dfs(col + 1, 0, ncarry):
                used[digit] = False
                del assigned[rch]
                return True
            used[digit] = False
            del assigned[rch]
            return False
        return dfs(0, 0, 0)

