var isSolvable = function(words, result) {
    const rows = words.concat([result]);
    for (const w of words) if (w.length > result.length) return false;
    const letters = new Set();
    for (const w of rows) for (const c of w) letters.add(c);
    if (letters.size > 10) return false;
    const leading = new Set();
    for (const w of rows) if (w.length > 1) leading.add(w[0]);
    const maxlen = result.length;
    const assigned = new Map();
    const used = new Array(10).fill(false);
    function dfs(col, row, carry) {
        if (col === maxlen) return carry === 0;
        if (row < words.length) {
            const w = words[row];
            if (col >= w.length) return dfs(col, row + 1, carry);
            const ch = w[w.length - 1 - col];
            if (assigned.has(ch)) return dfs(col, row + 1, carry + assigned.get(ch));
            for (let d = 0; d < 10; d++) {
                if (used[d] || (d === 0 && leading.has(ch))) continue;
                assigned.set(ch, d);
                used[d] = true;
                if (dfs(col, row + 1, carry + d)) { used[d] = false; assigned.delete(ch); return true; }
                used[d] = false;
                assigned.delete(ch);
            }
            return false;
        }
        const rch = result[maxlen - 1 - col];
        const digit = carry % 10;
        const ncarry = Math.floor(carry / 10);
        if (assigned.has(rch)) {
            if (assigned.get(rch) !== digit) return false;
            return dfs(col + 1, 0, ncarry);
        }
        if (used[digit] || (digit === 0 && leading.has(rch))) return false;
        assigned.set(rch, digit);
        used[digit] = true;
        if (dfs(col + 1, 0, ncarry)) { used[digit] = false; assigned.delete(rch); return true; }
        used[digit] = false;
        assigned.delete(rch);
        return false;
    }
    return dfs(0, 0, 0);
};
